INSERT INTO `question_bank` VALUES (1,1,'How are your job postings designed to attract candidates with disabilities?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:51:42',1),(2,1,'How accessible is your job application process to candidates with disabilities?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:52:18',2),(3,1,'What measures are in place to prevent disability bias during candidate screening',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:52:26',3),(4,1,'How does your organization ensure interviews are accessible and bias-free for PWD candidates?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:52:44',4),(5,1,'How does your organization ensure job selection criteria that do not unfairly exclude PWD candidates?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:52:47',5),(6,1,'Does your organization set and track hiring targets for persons with disabilities?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 10:11:12',6),(7,1,'Does your organization source candidates with disabilities?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:52:58',7),(8,1,'How are pre-employment asssessments (tests, tasks, exercises) made accessible to PWD candidates?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:53:09',8),(9,1,'How does, your organization handle the offer stage to ensure it is inclusive for PWD candidates?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:53:13',9),(10,1,'How does your organization track and use hiring data related to disability inclusion?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:53:18',10),(11,2,'How does your organization prepare for the arrival of a PWD new hire before their first day?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:01',11),(12,2,'How accessible are your orientation and onboarding materials to employees with disabilities?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:05',12),(13,2,'Does your organization assign a buddy or mentor to PWD new hires during the onboarding period?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:09',13),(14,2,'How quickly are accommodation needs addressed when identified during the onboarding period?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:14',14),(15,2,'Are managers trained and prepared to onboard an employee with a disability?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:18',15),(16,2,'How does your organization ensure PWD new hires have clear role expectations and performance goals from Day 1?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:24',16),(17,2,'How does your organization ensure the physical workplace orientation is accessible to all PWD new hires?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:28',17),(18,2,'How does your organization ensure PWD new hires can access all required digital systems and tools from Day 1?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:33',18),(19,2,'How does your organization introduce PWD new hires to their team in an inclusive way?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:39',19),(20,2,'How does your organization monitor the experience of PWD new hires during onboarding?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:43',20),(21,3,'Does your organization have a formal, written workplace accommodation policy?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:55:18',21),(22,3,'How clear and accessible is the process for employees to request a workplace accommodation?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:55:25',22),(23,3,'What is your organization\'s typical response time from accommodation request to resolution?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:55:31',23),(24,3,'Are managers trained to receive and act on accommodation requests without bias?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:55:36',24),(25,3,'What percentage of your office spaces are physically accessible to employees with mobility impairments?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:06',25),(26,3,'Are the digital tools your employees use daily audited for accessibility compliance?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 10:20:19',26),(27,3,'How does your organization support employees who need assistive technology (screen readers, voice recognition, ergonomic equipment, etc.)?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:17',27),(28,3,'How does your organization use flexible or remote work as an accommodation option for PWD employees?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:23',28),(29,3,'How does your organization protect the confidentiality and dignity of employees who disclose a disability or request accommodation?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:29',29),(30,3,'How does your organization review the effectiveness of accommodations already in place?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:36',30),(31,4,'How does your organization\'s voluntary attrition rate for PWD employees compare to the overall employee attrition rate?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:16',31),(32,4,'How does your organization ensure PWD employees have equitable access to career development and growth opportunities?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:28',32),(33,4,'Are PWD employees promoted at a rate equitable to their non-PWD peers at comparable performance levels?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:32',33),(34,4,'How does your organization ensure the performance management process is fair and accessible to PWD employees?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:35',34),(35,4,'Does your organization provide mentoring or sponsorship programs accessible to and inclusive of PWD employees?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:39',35),(36,4,'How does your organization use exit interview data to understand and reduce PWD employee turnover?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:43',36),(37,4,'How does your organization support PWD employees returning after a health-related or disability-related absence?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:47',37),(38,4,'How safe do PWD employees feel raising concerns, requesting accommodations, or disclosing disability status?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:52',38),(39,4,'How does your organization ensure PWD employees are included in team activities, informal networks, and social events?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:56:58',39),(40,4,'How does your organization demonstrate a long-term commitment to retaining PWD employees beyond initial placement?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:57:03',40),(41,5,'How visibly do senior leaders champion disability inclusion in your organization?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:33',41),(42,5,'Does your organization have a formal Disability Inclusion or DEI policy that specifically addresses disability?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:37',42),(43,5,'How does your organization promote and enforce inclusive, respectful language about disability?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:44',43),(44,5,'What disability awareness training do all employees receive?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:50',44),(45,5,'Does your organization have an ERG or affinity group for PWD employees and disability allies?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:55',45),(46,5,'How does your organization mark disability awareness moments (e.g., International Day of Persons with Disabilities)?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:54:59',46),(47,5,'How does your organization collect and act on feedback from PWD employees about the workplace culture?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:55:04',47),(48,5,'How does your organization extend its disability inclusion values to its supply chain and partners??',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:55:09',48),(49,5,'How does your organization celebrate and recognize the contributions of PWD employees?',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:55:15',49),(50,5,'How does your organization measure and continuously improve its disability inclusion culture??',1,1,NULL,'2026-04-20 08:04:32','2026-06-03 09:55:20',50),(52,1,'Job postings explicitly state that candidates with disabilities are encouraged to apply.',0,2,2,'2026-05-26 04:15:27','2026-06-03 09:51:39',1),(54,1,'Job descriptions include only essential functions, avoiding criteria that may inadvertently screen out qualified candidates with disabilities.',0,2,2,'2026-05-26 05:00:56','2026-06-03 09:52:14',2),(55,1,'The online job application platform has been audited for accessibility and meets a recognized standard (e.g., WCAG 2.1).',0,2,2,'2026-05-26 05:12:24','2026-06-03 09:52:26',3),(56,1,'Recruiting communications (email, interview invitations, assessments) are accessible to candidates using assistive technology.',0,2,2,'2026-05-26 05:31:05','2026-06-03 09:52:44',4),(57,1,'Interviewers and hiring managers receive disability awareness and inclusive hiring training.',0,2,2,'2026-05-26 05:38:53','2026-06-03 09:52:47',5),(58,1,'The organization has established measurable goals for recruiting employees with disabilities',0,2,2,'2026-05-26 05:42:20','2026-06-03 09:52:53',6),(59,1,'A needs assessment or gap analysis is conducted to identify roles where diverse talent, including people with disabilities, is underrepresented.',0,2,2,'2026-05-26 05:43:51','2026-06-03 09:52:58',7),(60,1,'The organization actively partners with disability-focused organizations, job boards, or vocational programs to source candidates.',0,2,2,'2026-05-26 05:47:02','2026-06-03 09:53:09',8),(61,1,'Pre-employment assessments and testing tools are reviewed for accessibility before use.',0,2,2,'2026-05-26 05:48:49','2026-06-03 09:53:13',9),(62,1,'Equal employment opportunity statements in all postings and diversity policies explicitly mention disability inclusion.',0,2,2,'2026-05-26 05:50:47','2026-06-03 09:53:18',10),(63,2,'Accessibility and disability inclusion training is formally included in the onboarding program for all new employees.',0,2,2,'2026-05-26 05:54:00','2026-06-03 09:54:01',11),(64,2,'New employees are informed of how to request accommodations during or immediately after onboarding.',0,2,2,'2026-05-26 05:55:37','2026-06-03 09:54:05',12),(65,2,'Onboarding materials (handbooks, forms, presentations, e-learning) are available in accessible formats.',0,2,2,'2026-05-26 05:56:57','2026-06-03 09:54:09',13),(66,2,'The onboarding process includes an introduction to the organization\'s accessibility policy and commitment to disability inclusion.',0,2,2,'2026-05-26 05:58:32','2026-06-03 09:54:14',14),(68,2,'New hires with disabilities are connected to relevant employee resource groups (ERGs) or support contacts during onboarding.',0,2,2,'2026-05-26 06:25:25','2026-06-03 09:54:18',15),(69,2,'Onboarding workflows include verification that an employee\'s workstation and tools are accessible before their first day.',0,2,2,'2026-05-26 06:26:52','2026-06-03 09:54:24',16),(70,2,'Career development paths, including required activities to advance, are communicated in accessible formats during onboarding.',0,2,2,'2026-05-26 06:28:00','2026-06-03 09:54:28',17),(71,2,'Onboarding includes training on internal accessibility tools and assistive technology available to employees.',0,2,2,'2026-05-26 06:29:03','2026-06-03 09:54:33',18),(72,2,'Managers who onboard new employees receive specific guidance on supporting employees with disclosed disabilities.',0,2,2,'2026-05-26 06:29:55','2026-06-03 09:54:39',19),(73,2,'The effectiveness of onboarding for employees with disabilities is periodically evaluated and improved.',0,2,2,'2026-05-26 06:30:51','2026-06-03 09:54:43',20),(74,3,'A written, publicly available policy exists for employees to request ICT-related and workplace accommodations.',0,2,2,'2026-05-26 06:32:48','2026-06-03 09:54:55',21),(75,3,'The accommodation request process is documented, straightforward, and accessible to employees with various disabilities.',0,2,2,'2026-05-26 06:33:48','2026-06-03 09:55:25',22),(76,3,'Tools and workflow systems are in place to facilitate, track, and fulfill accommodation requests in a timely manner.',0,2,2,'2026-05-26 06:34:59','2026-06-03 09:55:31',23),(77,3,'Employees are provided with support for the use of assistive technology needed to perform their job functions.',0,2,2,'2026-05-26 06:37:03','2026-06-03 09:55:36',24),(78,3,'The full range of accommodations is considered, including physical, digital, communication, and scheduling adjustments.',0,2,2,'2026-05-26 06:38:04','2026-06-03 09:56:06',25),(79,3,'Managers are trained to handle accommodation requests respectfully and in compliance with applicable law.',0,2,2,'2026-05-26 06:40:26','2026-06-03 09:56:12',26),(80,3,'An exception or risk-acceptance process exists for situations where a requested accommodation cannot immediately be met.',0,2,2,'2026-05-26 06:41:32','2026-06-03 09:56:17',27),(81,3,'Accommodations are reassessed periodically or when an employee\'s role changes, to ensure continued effectiveness.',0,2,2,'2026-05-26 06:42:59','2026-06-03 09:56:23',28),(82,3,'Employee feedback on accommodation experiences is collected and used to improve the process.',0,2,2,'2026-05-26 06:51:14','2026-06-03 09:56:29',29),(83,3,'Budget is specifically allocated to fund accommodations and assistive technology for employees with disabilities.',0,2,2,'2026-05-26 06:52:36','2026-06-03 09:56:36',30),(84,4,'Employees with disabilities hold roles at all levels and departments, including decision-making positions.',0,2,2,'2026-05-26 06:56:13','2026-06-03 09:56:16',31),(85,4,'A disability-focused employee resource group (ERG) with executive sponsorship exists and is actively leveraged.',0,2,2,'2026-05-26 06:57:35','2026-06-03 09:56:28',32),(86,4,'Employee performance evaluation criteria include accessibility-related responsibilities where relevant to the role.',0,2,2,'2026-05-26 06:59:45','2026-06-03 09:56:32',33),(87,4,'Mentoring programs are available and accessible to employees with disabilities.',0,2,2,'2026-05-26 07:01:57','2026-06-03 09:56:35',34),(88,4,'The organization tracks retention rates of employees with disabilities and uses data to drive improvement.',0,2,2,'2026-05-26 07:03:29','2026-06-03 09:56:39',35),(89,4,'Career advancement opportunities are equally accessible to employees with disabilities, with no systemic barriers.',0,2,2,'2026-05-26 07:04:37','2026-06-03 09:56:43',36),(90,4,'Employees with disabilities are actively included in product development, user research, and accessibility audits.',0,2,2,'2026-05-26 07:05:53','2026-06-03 09:56:47',37),(91,4,'Employee engagement surveys include questions about disability inclusion and accessibility support.',0,2,2,'2026-05-26 07:06:58','2026-06-03 09:56:52',38),(92,4,'A defined process exists for employees to raise accessibility-related concerns or complaints without fear of retaliation.',0,2,2,'2026-05-26 07:08:22','2026-06-03 09:56:58',39),(93,4,'Communities of practice or disability inclusion working groups exist to drive continuous improvement.',0,2,2,'2026-05-26 07:09:28','2026-06-03 09:57:03',40),(94,5,'Executive leadership has made a public statement affirming the organization\'s commitment to disability inclusion.',0,2,2,'2026-05-26 07:11:40','2026-06-03 09:54:33',41),(95,5,'An executive sponsor or senior leader is accountable for the accessibility and disability inclusion program.',0,2,2,'2026-05-26 07:12:50','2026-06-03 09:54:37',42),(96,5,'Disability inclusion and accessibility are explicitly embedded in the organization\'s core values and code of conduct.',0,2,2,'2026-05-26 07:13:56','2026-06-03 09:54:44',43),(97,5,'The organization\'s business strategy includes proactive, measurable goals for accessibility and disability inclusion.',0,2,2,'2026-05-26 07:15:06','2026-06-03 09:54:50',44),(98,5,'All employees receive general disability awareness and accessibility training relevant to their role.',0,2,2,'2026-05-26 07:16:10','2026-06-03 09:54:55',45),(99,5,'Disability inclusion is a recognized component of the broader diversity, equity, and inclusion (DEI) strategy.',0,2,2,'2026-05-26 07:17:07','2026-06-03 09:54:59',46),(100,5,'The organization measures and reports on accessibility program effectiveness, including cultural indicators.',0,2,2,'2026-05-26 07:21:28','2026-06-03 09:55:04',47),(101,5,'A financial plan and dedicated budget exist to advance accessibility maturity across all organizational dimensions.',0,2,2,'2026-05-26 07:22:31','2026-06-03 09:55:09',48),(102,5,'Digital accessibility performance is integrated into employee and officer performance objectives.',0,2,2,'2026-05-26 07:23:30','2026-06-03 09:55:15',49),(103,5,'The organization regularly captures employee feedback on disability inclusion and accessibility culture, and acts on results.',0,2,2,'2026-05-26 07:25:20','2026-06-03 09:55:20',50);
