INSERT INTO `question_choices` VALUES (1,1,'A','All postings explicitly welcome PWD applicants, state available accommodations, and are published on disability-inclusive job platforms.',4.00),(2,1,'B','Most postings include an equal opportunity statement and mention accommodation availability upon request.',3.00),(3,1,'C','We include generic equal opportunity clause but not actively communicate accommodation availability.',2.00),(4,1,'D','Job postings do not address disability inclusion or accommodation in any way.',1.00),(5,2,'A','Application process is fully accessible (WCAG 2.1 AA), tested with assistive technology, and offers multiple submission formats (online, email, phone).',4.00),(6,2,'B','Application is online and largely accessible; we offer alternative formats when specifically requested.',3.00),(7,2,'C','Application is online but has not been audited for accessibility; accommodations are handled case by case.',2.00),(8,2,'D','No accessibility audit has been done; we are unaware of any barriers in our application process.',1.00),(9,3,'A','Blind CV screening is standard; disability disclosure fields are removed before review; structured scoring rubrics are used by all reviewers.',4.00),(10,3,'B','We use structured rubrics and have trained screeners on unconscious bias, but disability details are still visible on CVs.',3.00),(11,3,'C','We have general unconscious bias training but no specific disability-focused screening protocols.',2.00),(12,3,'D','No structured screening process or bias-prevention measures are in place.',1.00),(13,4,'A','All interviewers receive disability inclusion training; candidates are proactively asked about accommodation needs before the interview; structured interview questions are used consistently.',4.00),(14,4,'B','We ask candidates about accommodations upon request and use structured questions, but interviewer training is not mandatory.',3.00),(15,4,'C','Accommodations are provided if a candidate asks, but we do not proactively offer them; interviewer training is ad-hoc.',2.00),(16,4,'D','No accommodation process for interviews; interviewers receive no disability-specific training.',1.00),(17,5,'A','All job requirements are reviewed for essential vs. non-essential functions; criteria are validated against actual job demands; adjustments are made where requirements can be met with reasonable accommodation.',4.00),(18,5,'B','HR reviews criteria for obvious exclusionary requirements but no formal validation process exists.',3.00),(19,5,'C','Selection criteria are set by hiring managers with no formal review for disability-related exclusion.',2.00),(20,5,'D','Selection criteria have never been reviewed through a disability inclusion lens.',1.00),(21,6,'A','We have formal, quantified PWD hiring targets, report progress quarterly, and link targets to leadership accountability.',4.00),(22,6,'B','We have informal hiring targets for PWDs and track progress annually.',3.00),(23,6,'C','We are aware of the need for PWD hiring targets but have not formally set them.',2.00),(24,6,'D','We have no hiring targets related to disability inclusion.',1.00),(25,7,'A','We have active partnerships with at least 3 disability-focused organizations (e.g., Virtualahan), attend disability job fairs, and maintain relationships with PWD communities.',4.00),(26,7,'B','We partner with 1–2 disability organizations and occasionally attend relevant job fairs.',3.00),(27,7,'C','We rely on general job boards and accept referrals from disability organizations when they come to us.',2.00),(28,7,'D','We have no active sourcing strategy targeting candidates with disabilities.',1.00),(29,8,'A','Assessments are designed to be disability-neutral by default, offered in accessible formats, and alternative assessment methods are available for all rules.',4.00),(30,8,'B','Accessible formats are available upon request and we adjust assessments case by case.',3.00),(31,8,'C','We make adjustments when a candidate specifically requests them, but our default assessments are not designed with accessibility in mind.',2.00),(32,8,'D','Pre-employment assessments have not been reviewed for accessibility.',1.00),(33,9,'A','Offer process includes proactive discussion of accommodation needs, flexible start dates, and documentation of agreed support before the first day.',4.00),(34,9,'B','We discuss accommodations during the offer stage when a candidate raises it.',3.00),(35,9,'C','Accommodations are discussed during onboarding, not the offer stage.',2.00),(36,9,'D','Accommodation needs are not formally discussed at any stage of the hiring process.',1.00),(37,10,'A','We collect voluntary disability disclosure data, track PWD hiring rates, analyze pipeline conversion at each stage, and report findings to leadership quarterly.',4.00),(38,10,'B','We collect voluntary disclosure data and track overall PWD hiring numbers annually.',3.00),(39,10,'C','We collect voluntary disclosure data but do not analyze it systematically.',2.00),(40,10,'D','We do not collect or track any disability-related hiring data.',1.00),(41,11,'A','A structured pre-boarding checklist is completed for every PWD hire: workstation assessed, assistive technology installed, buddy assigned, and all access needs confirmed in writing.',4.00),(42,11,'B','We confirm accommodation needs before Day 1 and make basic preparations, but no formal checklist is used.',3.00),(43,11,'C','We prepare for PWD new hires on a case-by-case basis with no standard process.',2.00),(44,11,'D','No specific pre-boarding preparation is made for PWD new hires beyond standard onboarding.',1.00),(45,12,'A','All orientation materials (documents, videos, presentations) meet WCAG 2.1 AA standards, are available in multiple formats (screen-reader friendly, captioned, large print), and have been tested by a PWD.',4.00),(46,12,'B','Most materials are in digital format and generally accessible; we provide alternative formats upon request.',3.00),(47,12,'C','Materials are in standard digital formats that have not been audited for accessibility.',2.00),(48,12,'D','Orientation materials are print-based or use formats that have not been reviewed for accessibility.',1.00),(49,13,'A','All PWD new hires are assigned a trained inclusion buddy who checks in weekly for the first 90 days; buddy training is mandatory and documented.',4.00),(50,13,'B','We assign a buddy to PWD new hires but buddy training is informal and check-ins are not structured.',3.00),(51,13,'C','A buddy is assigned to all new hires (not PWD-specific); no specialized preparation for supporting PWD colleagues.',2.00),(52,13,'D','No buddy or mentor system exists during onboarding.',1.00),(53,14,'A','All accommodation requests raised during onboarding are resolved within 5 business days; a single point of contact (accommodation coordinator) manages the process.',4.00),(54,14,'B','Accommodations are addressed within 2 weeks; HR manages the process but no dedicated coordinator exists.',3.00),(55,14,'C','Accommodations are addressed eventually but with no defined timeline; the process varies by manager.',2.00),(56,14,'D','Accommodation needs raised during onboarding are not tracked or managed systematically.',1.00),(57,15,'A','All managers whose teams include PWD hires complete mandatory disability inclusion and onboarding training before the employee\'s first day; training is assessed and documented.',4.00),(58,15,'B','Managers receive disability awareness training as part of general management development, but it is not specifically timed to a PWD hire.',3.00),(59,15,'C','Training is available but optional; not all relevant managers have completed it.',2.00),(60,15,'D','Managers receive no specific training on onboarding employees with disabilities.',1.00),(61,16,'A','Structured 30-60-90 day plans are co-created with every new hire including PWDs; plans explicitly account for any adjustment period and are reviewed by HR.',4.00),(62,16,'B','30-60-90 day plans are used for most new hires; PWD-specific adjustments are made when raised.',3.00),(63,16,'C','Role expectations are communicated verbally; no structured written plan is standard.',2.00),(64,16,'D','New hires are expected to figure out role expectations through observation and informal guidance.',1.00),(65,17,'A','A personalized physical orientation is conducted for every PWD new hire, covering all accessible routes, facilities, emergency evacuation procedures (with personalized plan), and assistive equipment locations.',4.00),(66,17,'B','Physical orientation covers main areas; personalized accessibility routes are shown when needed.',3.00),(67,17,'C','Standard workplace tour is provided to all new hires with no disability-specific adaptation.',2.00),(68,17,'D','No formal workplace orientation is provided.',1.00),(69,18,'A','All required systems are pre-configured for accessibility before the employee\'s start date; IT conducts a personalized accessibility setup session within the first week',4.00),(70,18,'B','Standard IT setup is completed before Day 1; accessibility settings are configured when the employee requests them.',3.00),(71,18,'C','IT setup is completed, but accessibility configurations are left to the employee to figure out.',2.00),(72,18,'D','IT setup is often delayed for new hires; no accessibility review of digital tools is done.',1.00),(73,19,'A','Team introductions follow a structured inclusion protocol: team is briefed on respectful communication before the new hire arrives; introduction formats are agreed with the new hire in advance.',4.00),(74,19,'B','Team introductions happen naturally; managers remind teams of respectful communication principles informally',3.00),(75,19,'C','New hires are introduced to teams at the manager\'s discretion with no structured protocol',2.00),(76,19,'D','No specific approach to team introductions for PWD new hires exists.',1.00),(77,20,'A','Structured check-ins occur at Day 7, Day 30, and Day 90 with both HR and the line manager; feedback is documented and any concerns trigger a formal response process.',4.00),(78,20,'B','At least one formal HR check-in occurs within the first 30 days for PWD new hires.',3.00),(79,20,'C','Manager check-ins happen informally; no structured HR review of the onboarding experience.',2.00),(80,20,'D','No formal check-in process exists; issues surface only when the employee raises them.',1.00),(81,21,'A','A comprehensive written accommodation policy exists, is reviewed annually, is accessible on the company intranet, and is communicated to all employees during onboarding.',4.00),(82,21,'B','A written accommodation policy exists but is not prominently communicated or regularly reviewed.',3.00),(83,21,'C','We follow accommodation practices informally but have no documented policy.',2.00),(84,21,'D','No accommodation policy exists in any form.',1.00),(85,22,'A','A clearly documented, step-by-step accommodation request process is available in multiple accessible formats; employees know exactly who to contact and what to expect at each stage.',4.00),(86,22,'B','A process exists and is documented, but awareness among employees is low.',3.00),(87,22,'C','Employees can request accommodations but must navigate an unclear, inconsistent process.',2.00),(88,22,'D','No formal request process exists; employees must advocate for themselves without guidance.',1.00),(89,23,'A','All requests are acknowledged within 2 business days and fully resolved within 10 business days; response time is tracked and reported.',4.00),(90,23,'B','Most requests are resolved within 3 weeks; response time is not formally tracked.',3.00),(91,23,'C','Resolution typically takes 4–6 weeks and varies significantly by department or manager.',2.00),(92,23,'D','Resolution time is unpredictable and often exceeds 6 weeks or requests are left unresolved.',1.00),(93,24,'A','All managers complete mandatory accommodation training annually; training covers legal obligations, bias awareness, and practical response steps; completion is tracked.',4.00),(94,24,'B','Accommodation training is available and most managers have completed it, but it is not mandatory.',3.00),(95,24,'C','General disability awareness training exists but does not cover accommodation processes specifically.',2.00),(96,24,'D','No accommodation or disability-related training is provided to managers.',1.00),(97,25,'A','100% of office spaces are accessible: accessible entrances, elevators, restrooms, workstations, and emergency evacuation plans for all mobility needs.',4.00),(98,25,'B','75–99% of spaces are accessible; minor gaps exist and are documented with remediation plans.',3.00),(99,25,'C','50–74% of spaces are accessible; significant barriers remain in some areas.',2.00),(100,25,'D','Less than 50% of spaces are accessible or accessibility has not been formally assessed.',1.00),(101,26,'A','All primary digital tools are audited against WCAG 2.1 AA annually; findings are remediated within a defined timeline; accessibility is a procurement requirement for new tools.',4.00),(102,26,'B','Key tools have been assessed for accessibility; gaps are known but remediation is slow.',3.00),(103,26,'C','Some tools have been assessed informally; no systematic audit process exists.',2.00),(104,26,'D','Digital tools have never been assessed for accessibility compliance.',1.00),(105,27,'A','A catalog of available assistive technology is maintained; equipment is provided at no cost to the employee within 5 business days of request; IT provides setup support.',4.00),(106,27,'B','Assistive technology is procured on request; the process works but takes 2–4 weeks.',3.00),(107,27,'C','Assistive technology can be requested but the process is unclear and slow.',2.00),(108,27,'D','No formal process or budget exists for assistive technology procurement.',1.00),(109,28,'A','Flexible and remote work are formally recognized as accommodation options; policies explicitly include these arrangements; they are granted without stigma when requested for disability-related reasons.',4.00),(110,28,'B','Flexible/remote work is available as an accommodation but requires manager approval on a case-by-case basis.',3.00),(111,28,'C','Flexible/remote work is theoretically available but not commonly granted as an accommodation.',2.00),(112,28,'D','Flexible/remote work is not recognized as a formal accommodation option.',1.00),(113,29,'A','Strict confidentiality protocols are in place: disclosure is shared only with those with operational need to know; consent is obtained before any sharing; employees are trained on their rights.',4.00),(114,29,'B','Confidentiality is maintained by HR but protocols are not formally documented or communicated to employees.',3.00),(115,29,'C','Confidentiality is expected but not formally governed; practices vary by manager.',2.00),(116,29,'D','No formal confidentiality protocols exist for disability disclosure or accommodation requests.',1.00),(117,30,'A','Accommodations are reviewed at least annually in partnership with the employee; reviews are documented and adjustments are made proactively as roles or needs change.',4.00),(118,30,'B','Accommodations are reviewed when the employee raises a concern or when a role changes.',3.00),(119,30,'C','Accommodations are rarely reviewed after initial implementation unless a problem arises.',2.00),(120,30,'D','No review process exists; accommodations, once implemented, are never formally revisited.',1.00),(121,31,'A','PWD voluntary attrition is at or below the overall organizational attrition rate; data is tracked quarterly and any gap triggers an immediate review.',4.00),(122,31,'B','PWD attrition is slightly higher (up to 10% above org average) and is monitored annually.',3.00),(123,31,'C','PWD attrition is 10–25% higher than org average; the gap is known but no formal intervention plan exists.',2.00),(124,31,'D','PWD attrition is more than 25% above org average, or attrition is not tracked by disability status at all.',1.00),(125,32,'A','PWD employees participate in career development programs at the same rate as non-PWD peers; participation is tracked; any gap triggers targeted outreach.',4.00),(126,32,'B','Career development opportunities are available to all employees; PWD participation is not specifically tracked.',3.00),(127,32,'C','PWD employees have access to standard career development programs but face informal barriers (scheduling, format, awareness).',2.00),(128,32,'D','Career development access for PWD employees is not monitored; disparities are likely but unconfirmed.',1.00),(129,33,'A','Promotion rates for PWD employees are tracked and benchmarked against non-PWD peers; any gap is formally investigated and remediated.',4.00),(130,33,'B','Promotion rates are not broken down by disability status but the process is designed to be objective.',3.00),(131,33,'C','We believe promotions are equitable but have no data to confirm or deny disparities.',2.00),(132,33,'D','We have not analyzed promotion equity by disability status and disparities may exist.',1.00),(133,34,'A','Performance frameworks are reviewed for disability-related bias annually; accommodation needs are factored into goal-setting; managers are trained on equitable performance evaluation for PWD employees.',4.00),(134,34,'B','Standard performance management applies to all employees; managers are aware of the need to factor in accommodations but receive no formal training.',3.00),(135,34,'C','Performance management is standardized; no specific adjustments or bias reviews for PWD employees.',2.00),(136,34,'D','Performance management has not been reviewed for accessibility or PWD-related equity.',1.00),(137,35,'A','A formal mentoring program exists, actively recruits PWD participants, includes disability-aware mentor training, and tracks PWD participation rates.',4.00),(138,35,'B','A mentoring program exists and is open to all; PWD employees can participate but are not specifically targeted or tracked.',3.00),(139,35,'C','Informal mentoring exists through personal networks; no structured program is in place',2.00),(140,35,'D','No mentoring or sponsorship program exists in the organization.',1.00),(141,36,'A','Exit interviews are conducted for all departing PWD employees; disability-related turnover reasons are tracked separately; findings are reported to leadership and drive specific retention interventions.',4.00),(142,36,'B','Exit interviews are conducted for all employees; disability-related trends are occasionally reviewed.',3.00),(143,36,'C','Exit interviews are conducted but disability status is not captured or analyzed separately.',2.00),(144,36,'D','Exit interviews are not conducted consistently or the data is not analyzed.',1.00),(145,37,'A','A formal return-to-work program exists: phased return plans, accommodation review upon return, dedicated HR support, and manager briefing before the employee\'s return date',4.00),(146,37,'B','Return-to-work is handled by HR on a case-by-case basis; some structure exists but it varies.',3.00),(147,37,'C','Returning employees are expected to resume normal duties; informal support is available on request.',2.00),(148,37,'D','No formal return-to-work process exists; employees return without structured support.',1.00),(149,38,'A','Regular anonymous surveys measure psychological safety specifically for PWD employees; results are reviewed by leadership; any decline triggers immediate action.',4.00),(150,38,'B','General employee satisfaction surveys include some inclusion questions; PWD-specific data is not isolated.',3.00),(151,38,'C','We believe the environment is safe but have no data or formal mechanism to measure it.',2.00),(152,38,'D','No mechanism exists to measure psychological safety for PWD employees.',1.00),(153,39,'A','All team events and social activities are reviewed for accessibility before scheduling; PWD employees are consulted; inaccessible events are adapted or alternatives are offered.',4.00),(154,39,'B','Accessibility of team events is considered but not systematically reviewed; gaps are addressed when flagged.',3.00),(155,39,'C','Team events default to standard formats; PWD employees must raise accessibility concerns themselves.',2.00),(156,39,'D','Accessibility of social and team activities is not considered in planning.',1.00),(157,40,'A','Retention of PWD employees is a stated organizational goal with named executive ownership; 12-month and 24-month retention rates for PWD employees are tracked and reported.',4.00),(158,40,'B','PWD retention is valued informally; some tracking occurs but no formal goal or executive accountability exists.',3.00),(159,40,'C','Retention of PWD employees is discussed but treated as the responsibility of the immediate manager only.',2.00),(160,40,'D','No specific focus on long-term retention of PWD employees exists at an organizational level.',1.00),(161,41,'A','Senior leaders publicly champion disability inclusion through visible actions (internal communications, participation in disability awareness events, public statements); inclusion is a standing agenda item at leadership meetings.',4.00),(162,41,'B','Some senior leaders champion inclusion informally; it is raised occasionally at leadership level.',3.00),(163,41,'C','Disability inclusion is delegated entirely to HR; senior leaders are supportive in principle but not visibly active.',2.00),(164,41,'D','Disability inclusion is not a leadership priority and is rarely mentioned by senior leaders.',1.00),(165,42,'A','A formal, disability-specific inclusion policy exists, is reviewed annually, is accessible to all employees, and has named accountability (e.g., a DEI officer or committee).',4.00),(166,42,'B','A general DEI policy exists that mentions disability; it is accessible but rarely reviewed.',3.00),(167,42,'C','A generic equal opportunity policy exists; disability is implied but not specifically addressed.',2.00),(168,42,'D','No formal DEI or disability inclusion policy exists.',1.00),(169,43,'A','An inclusive language guide specific to disability is available; managers are trained to address non-inclusive language immediately; the guide is reviewed and updated annually.',4.00),(170,43,'B','General communication guidelines exist that touch on respectful language; no disability-specific guidance.',3.00),(171,43,'C','Inclusive language is encouraged informally but there is no formal guidance or enforcement mechanism.',2.00),(172,43,'D','No guidance on inclusive language related to disability exists.',1.00),(173,44,'A','All employees complete mandatory disability awareness training annually; training covers respectful language, allyship, unconscious bias, and practical inclusion behaviors; completion is tracked.',4.00),(174,44,'B','Disability awareness training is available and most employees have completed it, but it is not mandatory.',3.00),(175,44,'C','Training is available but participation is low; it is not promoted or tracked.',2.00),(176,44,'D','No disability awareness training is provided to general employees.',1.00),(177,45,'A','A PWD ERG exists with dedicated budget, executive sponsorship, formal recognition, and regular programming; ERG input is sought in organizational decision-making.',4.00),(178,45,'B','A PWD ERG or informal group exists but has limited budget and no formal executive sponsorship.',3.00),(179,45,'C','Interest in forming a PWD ERG has been expressed but no group has been established.',2.00),(180,45,'D','No ERG or affinity group related to disability exists.',1.00),(181,46,'A','Annual disability awareness programming is planned and resourced; includes internal events, PWD speaker series, and employee communications; outcomes are measured.',4.00),(182,46,'B','The organization marks key awareness dates with internal communications and occasional events.',3.00),(183,46,'C','Awareness dates are acknowledged informally by some teams but not organizationally.',2.00),(184,46,'D','Disability awareness events or dates are not recognized by the organization.',1.00),(185,47,'A','Disaggregated PWD employee feedback is collected through regular surveys; results are shared transparently; action plans are developed and tracked publicly.',4.00),(186,47,'B','General employee surveys include inclusion questions; PWD-specific results are not isolated or shared.',3.00),(187,47,'C','Feedback is collected informally; no mechanism exists to capture disability-specific cultural feedback.',2.00),(188,47,'D','No formal mechanism exists to collect feedback from PWD employees.',1.00),(189,48,'A','Disability inclusion standards are embedded in supplier and partner selection criteria; partners are assessed and encouraged to adopt similar inclusion practices.',4.00),(190,48,'B','We communicate our values to partners and prefer inclusive suppliers when all else is equal.',3.00),(191,48,'C','Our inclusion standards apply internally only; we have not extended them to the supply chain.',2.00),(192,48,'D','Disability inclusion is not considered in supplier or partner relationships.',1.00),(193,49,'A','PWD employee stories and achievements are shared internally with consent; PWD employees are featured in organizational communications, awards, and recognition programs?',4.10),(194,49,'B','PWD employees are recognized through general recognition programs; no specific highlighting of their inclusion journey or contributions.',3.00),(195,49,'C','Recognition programs exist but PWD employees are rarely featured or highlighted.',2.00),(196,49,'D','Recognition programs do not consider disability inclusion perspectives.',1.00),(197,50,'A','Disability inclusion culture is measured annually using a validated instrument; scores are benchmarked against industry peers; a formal improvement plan with named owners and timelines is updated each year.',4.00),(198,50,'B','Cultural inclusion is measured through general engagement surveys; disability-specific trends are reviewed when possible.',3.00),(199,50,'C','We conduct periodic reviews of our culture informally but have no structured measurement tool.',2.00),(200,50,'D','Disability inclusion culture is not formally measured or tracked.',1.00),(208,52,'A','Not in Place',1.00),(209,52,'B','Planned',2.00),(210,52,'C','Partially Done',3.00),(211,52,'D','Fully Established',4.00),(222,54,'A','Not in Place',1.00),(223,54,'B','Planned',2.00),(224,54,'C','Partially Done',3.00),(225,54,'D','Fully Established',4.00),(229,55,'A','Not in Place',1.00),(230,55,'B','Planned',2.00),(231,55,'C','Partially Done',3.00),(232,55,'D','Fully Established',4.00),(236,56,'A','Not in Place',1.00),(237,56,'B','Planned',2.00),(238,56,'C','Partially Done',3.00),(239,56,'D','Fully Established',4.00),(243,57,'A','Not in Place',1.00),(244,57,'B','Planned',2.00),(245,57,'C','Partially Done',3.00),(246,57,'D','Fully Established',4.00),(250,58,'A','Not in Place',1.00),(251,58,'B','Planned',2.00),(252,58,'C','Partially Done',3.00),(253,58,'D','Fully Established',4.00),(257,59,'A','Not in Place',1.00),(258,59,'B','Planned',2.00),(259,59,'C','Partially Done',3.00),(260,59,'D','Fully Established',4.00),(264,60,'A','Not in Place',1.00),(265,60,'B','Planned',2.00),(266,60,'C','Partially Done',3.00),(267,60,'D','Fully Established',4.00),(271,61,'A','Not in Place',1.00),(272,61,'B','Planned',2.00),(273,61,'C','Partially Done',3.00),(274,61,'D','Fully Established',4.00),(278,62,'A','Not in Place',1.00),(279,62,'B','Planned',2.00),(280,62,'C','Partially Done',3.00),(281,62,'D','Fully Established',4.00),(285,63,'A','Not in Place',1.00),(286,63,'B','Planned',2.00),(287,63,'C','Partially Done',3.00),(288,63,'D','Fully Established',4.00),(292,64,'A','Not in Place',1.00),(293,64,'B','Planned',2.00),(294,64,'C','Partially Done',3.00),(295,64,'D','Fully Established',4.00),(299,65,'A','Not in Place',1.00),(300,65,'B','Planned',2.00),(301,65,'C','Partially Done',3.00),(302,65,'D','Fully Established',4.00),(306,66,'A','Not in Place',1.00),(307,66,'B','Planned',2.00),(308,66,'C','Partially Done',3.00),(309,66,'D','Fully Established',4