INSERT INTO `system_settings` VALUES ('approval_reviewer','both',NULL,'2026-06-10 05:11:45'),('auto_send_approval_email','on',NULL,'2026-06-10 05:11:45'),('auto_send_rejection_email','',NULL,'2026-06-10 05:11:45'),('email_approval_body','Hello {contact_person},\r\n\r\nYour organization, {company_name}, has been approved for the {system_name}.\r\n\r\nYou may now log in using your registered work email:\r\n{work_email}\r\n\r\nLogin page:\r\n{login_url}\r\n\r\nThank you,\r\n{primary_contact}',NULL,'2026-06-10 05:11:45'),('email_approval_subject','Account Approved - {system_name}',NULL,'2026-06-10 05:11:45'),('email_invitation_body','Hello,\r\n\r\nYou are invited to register in the {system_name}.\r\n\r\nPlease complete your organization registration using this link:\r\n{registration_url}\r\n\r\nThank you,\r\n{primary_contact}',NULL,'2026-06-10 05:11:45'),('email_invitation_subject','Registration Invitation - Inclusion Intelligence',NULL,'2026-06-10 05:11:45'),('email_password_reset_body','Hello {contact_person},\r\n\r\nWe received a request to reset the password associated with your {system_name} account.\r\n\r\nPlease use the link below to create a new password:\r\n{reset_url}\r\n\r\nFor security purposes, this link will expire in 15 minutes.\r\n\r\nIf you did not request a password reset, you may safely ignore this email.\r\n\r\nThank you,\r\n{primary_contact}',NULL,'2026-06-10 05:11:45'),('email_password_reset_subject','Reset Your Password - {system_name}',NULL,'2026-06-10 05:11:45'),('email_rejection_body','Hello {contact_person},\r\n\r\nYour access request for {company_name} was not approved.\r\n\r\nReason:\r\n{rejection_reason}\r\n\r\nFor questions, please contact {support_email}.\r\n\r\nThank you,\r\n{primary_contact}',NULL,'2026-06-10 05:11:45'),('email_rejection_subject','Access Request Update - {system_name}',NULL,'2026-06-10 05:11:45'),('email_verification_body','Hello {contact_person},\r\n\r\nPlease verify your email address to continue your {system_name} registration.\r\n\r\nVerification link:\r\n{verification_url}\r\n\r\nThis link will expire in 24 hours. Once verified, your access request will be sent to the administrator for approval.\r\n\r\nThank you,\r\n{primary_contact}',NULL,'2026-06-10 05:11:45'),('email_verification_subject','Verify Your Email - {system_name}',NULL,'2026-06-10 05:11:45'),('gap_critical_score_max','1',NULL,'2026-06-10 05:11:45'),('gap_low_score_max','3',NULL,'2026-06-10 05:11:45'),('gap_moderate_score_max','2',NULL,'2026-06-10 05:11:45'),('password_min_length','8',NULL,'2026-06-10 05:11:45'),('primary_contact','Virtualahan Admin Team',NULL,'2026-06-10 05:11:45'),('reassessment_lock_days','182',NULL,'2026-06-10 05:11:45'),('report_footer_text','Prepared by Inclusion Intelligence System',NULL,'2026-06-10 05:11:45'),('report_include_generated_date','on',NULL,'2026-06-10 05:11:45'),('report_show_gap_analysis','on',NULL,'2026-06-10 05:11:45'),('report_show_recommendations','on',NULL,'2026-06-10 05:11:45'),('require_rejection_reason','on',NULL,'2026-06-10 05:11:45'),('score_advancing_max','75',NULL,'2026-06-10 05:11:45'),('score_developing_max','50',NULL,'2026-06-10 05:11:45'),('score_emerging_max','25',NULL,'2026-06-10 05:11:45'),('score_leading_max','90',NULL,'2026-06-10 05:11:45'),('session_timeout_minutes','60',NULL,'2026-06-10 05:11:45'),('support_email','iis@virtualahan.com',NULL,'2026-06-10 05:11:45'),('suspend_deactivate_admins','on',NULL,'2026-06-10 05:11:45'),('suspend_hide_reports','on',NULL,'2026-06-10 05:11:45'),('suspend_lock_assessments','on',NULL,'2026-06-10 05:11:45'),('system_name','Inclusion Intelligence System',NULL,'2026-06-10 05:11:45'),('weight_accommodation','20',NULL,'2026-06-10 05:11:45'),('weight_culture','20',NULL,'2026-06-10 05:11:45'),('weight_hiring','20',NULL,'2026-06-10 05:11:45'),('weight_onboarding','20',NULL,'2026-06-10 05:11:45'),('weight_retention','20',NULL,'2026-06-10 05:11:45');
